module top_module(
    input wire clk,
    input wire rst,
    output reg [3:0] random
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if(rst)
            random<=4'b1000;
        else begin
            random[2:0]<=random[3:1];
            random[3]<=random[1]^random[0];
        end
    end
endmodule
